export async function render(value, options, api) {
  const { mode, onChange, label, indent = 0 } = options;
  const obj = value || {};
  const isEditable = mode === 'editable' && onChange;

  const wrapper = api.createElement('div', { class: 'field-object' });
  wrapper.style.cssText = 'display: flex; flex-direction: column; gap: 8px;';

  if (label) {
    const labelEl = api.createElement('div');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-weight: 600; font-size: 14px; color: #333; margin-bottom: 4px;';
    wrapper.appendChild(labelEl);
  }

  const propsContainer = api.createElement('div');
  propsContainer.style.cssText = 'display: flex; flex-direction: column; gap: 12px; padding-left: ' + (indent > 0 ? '16px' : '0') + '; border-left: ' + (indent > 0 ? '2px solid #e0e0e0' : 'none') + ';';

  // Helper to update a property
  const updateProp = (key, newValue) => {
    const updated = { ...obj, [key]: newValue };
    onChange(updated);
  };

  // Helper to delete a property
  const deleteProp = (key) => {
    const updated = { ...obj };
    delete updated[key];
    onChange(updated);
  };

  // Helper to rename a property
  const renameProp = (oldKey, newKey) => {
    if (oldKey === newKey || !newKey) return;
    const updated = {};
    for (const k of Object.keys(obj)) {
      if (k === oldKey) {
        updated[newKey] = obj[oldKey];
      } else {
        updated[k] = obj[k];
      }
    }
    onChange(updated);
  };

  // Render each property
  const keys = Object.keys(obj);
  for (const key of keys) {
    const val = obj[key];
    const propRow = api.createElement('div', { class: 'field-object-prop' });
    propRow.style.cssText = 'display: flex; flex-direction: column; gap: 4px;';

    // Property header with key name and delete button
    const propHeader = api.createElement('div');
    propHeader.style.cssText = 'display: flex; align-items: center; gap: 8px;';

    if (isEditable) {
      // Editable key name
      const keyInput = api.createElement('input', { type: 'text' });
      keyInput.value = key;
      keyInput.style.cssText = 'font-weight: 500; font-size: 13px; color: #555; background: transparent; border: 1px solid transparent; border-radius: 3px; padding: 2px 4px; width: auto; min-width: 80px;';
      keyInput.onblur = () => renameProp(key, keyInput.value.trim());
      keyInput.onkeydown = (e) => { if (e.key === 'Enter') keyInput.blur(); };
      propHeader.appendChild(keyInput);

      // Delete button
      const deleteBtn = api.createElement('button');
      deleteBtn.textContent = '\u00d7';
      deleteBtn.style.cssText = 'background: none; border: none; color: #999; cursor: pointer; font-size: 16px; padding: 0 4px; line-height: 1;';
      deleteBtn.onclick = () => deleteProp(key);
      deleteBtn.title = 'Remove property';
      propHeader.appendChild(deleteBtn);
    } else {
      const keyLabel = api.createElement('span');
      keyLabel.textContent = key;
      keyLabel.style.cssText = 'font-weight: 500; font-size: 13px; color: #555;';
      propHeader.appendChild(keyLabel);
    }

    propRow.appendChild(propHeader);

    // Render value based on type
    const valType = Array.isArray(val) ? 'array' : typeof val;
    let fieldEl;

    try {
      if (valType === 'string') {
        // Check if it looks like a GUID (item reference)
        const guidPattern = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
        if (guidPattern.test(val)) {
          const fieldView = await api.require('field-view-item-ref');
          fieldEl = await fieldView.render(val, {
            mode,
            onChange: isEditable ? (v) => updateProp(key, v) : null
          }, api);
        } else if (val.length > 100 || val.includes('\n')) {
          // Use textarea for long strings or strings with newlines
          const fieldView = await api.require('field-view-textarea');
          fieldEl = await fieldView.render(val, {
            mode,
            onChange: isEditable ? (v) => updateProp(key, v) : null
          }, api);
        } else {
          const fieldView = await api.require('field-view-text');
          fieldEl = await fieldView.render(val, {
            mode,
            onChange: isEditable ? (v) => updateProp(key, v) : null
          }, api);
        }
      } else if (valType === 'number') {
        const fieldView = await api.require('field-view-number');
        fieldEl = await fieldView.render(val, {
          mode,
          onChange: isEditable ? (v) => updateProp(key, v) : null
        }, api);
      } else if (valType === 'boolean') {
        const fieldView = await api.require('field-view-checkbox');
        fieldEl = await fieldView.render(val, {
          mode,
          onChange: isEditable ? (v) => updateProp(key, v) : null
        }, api);
      } else if (valType === 'object' && val !== null) {
        // Recursively render nested objects
        fieldEl = await render(val, {
          mode,
          onChange: isEditable ? (v) => updateProp(key, v) : null,
          indent: indent + 1
        }, api);
      } else {
        // Arrays and other types: fall back to JSON
        const fieldView = await api.require('field-view-json');
        fieldEl = await fieldView.render(val, {
          mode,
          onChange: isEditable ? (v) => updateProp(key, v) : null
        }, api);
      }
    } catch (e) {
      // Fallback if field view not found
      fieldEl = api.createElement('span');
      fieldEl.textContent = JSON.stringify(val);
      fieldEl.style.cssText = 'font-family: monospace; font-size: 13px;';
    }

    propRow.appendChild(fieldEl);
    propsContainer.appendChild(propRow);
  }

  wrapper.appendChild(propsContainer);

  // Add property button (only in editable mode)
  if (isEditable) {
    const addRow = api.createElement('div');
    addRow.style.cssText = 'margin-top: 8px;';

    const addBtn = api.createElement('button');
    addBtn.textContent = '+ Add Property';
    addBtn.style.cssText = 'padding: 4px 12px; font-size: 12px; cursor: pointer; background: #f5f5f5; border: 1px solid #ddd; border-radius: 4px; color: #555;';
    addBtn.onclick = () => {
      // Generate unique key name
      let newKey = 'newProperty';
      let i = 1;
      while (obj.hasOwnProperty(newKey)) {
        newKey = 'newProperty' + i++;
      }
      onChange({ ...obj, [newKey]: '' });
    };
    addRow.appendChild(addBtn);
    wrapper.appendChild(addRow);
  }

  // Show empty state
  if (keys.length === 0 && !isEditable) {
    const emptyEl = api.createElement('div');
    emptyEl.textContent = '(empty object)';
    emptyEl.style.cssText = 'color: #999; font-style: italic; font-size: 13px;';
    propsContainer.appendChild(emptyEl);
  }

  return wrapper;
}

/**
 * Shared modal library for consistent modal dialogs across Hobson.
 * Handles: backdrop, centering, Escape key, click-outside-to-close.
 */

/**
 * Shows a modal dialog with the provided content.
 * @param {Object} options - Modal options
 * @param {HTMLElement|Function} options.content - Content element or function that receives { close } and returns element
 * @param {string} [options.title] - Optional title for the modal header
 * @param {string} [options.width='500px'] - Modal width
 * @param {string} [options.maxHeight='80vh'] - Modal max height
 * @param {boolean} [options.showCloseButton=true] - Show X close button in header
 * @param {boolean} [options.closeOnBackdrop=true] - Close when clicking backdrop
 * @param {boolean} [options.closeOnEscape=true] - Close when pressing Escape
 * @param {Function} [options.onClose] - Callback when modal is closed
 * @param {Object} [options.api] - Hobson API (uses document.createElement if not provided)
 * @returns {{ close: Function, overlay: HTMLElement, modalBox: HTMLElement }}
 */
export function showModal(options = {}) {
  const {
    content,
    title,
    width = '500px',
    maxHeight = '80vh',
    showCloseButton = true,
    closeOnBackdrop = true,
    closeOnEscape = true,
    onClose,
    api
  } = options;

  // Use api.createElement if available, otherwise document.createElement
  const createElement = api?.createElement
    ? (tag, props, children) => api.createElement(tag, props, children || [])
    : (tag, props, children) => {
        const el = document.createElement(tag);
        if (props) {
          for (const [key, value] of Object.entries(props)) {
            if (key === 'style') {
              el.style.cssText = value;
            } else if (key.startsWith('on') && typeof value === 'function') {
              el.addEventListener(key.substring(2).toLowerCase(), value);
            } else {
              el.setAttribute(key, value);
            }
          }
        }
        if (children) {
          for (const child of children) {
            if (typeof child === 'string') {
              el.appendChild(document.createTextNode(child));
            } else if (child instanceof Node) {
              el.appendChild(child);
            }
          }
        }
        return el;
      };

  let isClosing = false;

  // Close function
  const close = () => {
    if (isClosing) return;
    isClosing = true;

    // Remove escape handler
    if (escapeHandler) {
      document.removeEventListener('keydown', escapeHandler);
    }

    // Remove overlay
    if (overlay.parentNode) {
      overlay.parentNode.removeChild(overlay);
    }

    // Call onClose callback
    if (onClose) {
      onClose();
    }
  };

  // Create overlay
  const overlay = createElement('div', {
    style: `
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, 0.5);
      display: flex;
      align-items: center;
      justify-content: center;
      z-index: 10000;
    `
  });

  // Create modal box
  const modalBox = createElement('div', {
    style: `
      background: white;
      border-radius: 8px;
      width: ${width};
      max-width: 90vw;
      max-height: ${maxHeight};
      overflow: auto;
      box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
      display: flex;
      flex-direction: column;
    `
  });

  // Add header if title is provided
  if (title || showCloseButton) {
    const header = createElement('div', {
      style: `
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 16px 20px;
        border-bottom: 1px solid #e0e0e0;
        flex-shrink: 0;
      `
    });

    if (title) {
      const titleEl = createElement('h3', {
        style: 'margin: 0; font-size: 18px; font-weight: 600; color: #333;'
      }, [title]);
      header.appendChild(titleEl);
    } else {
      header.appendChild(createElement('div'));
    }

    if (showCloseButton) {
      const closeBtn = createElement('button', {
        style: `
          padding: 4px 8px;
          cursor: pointer;
          background: transparent;
          border: none;
          font-size: 20px;
          color: #666;
          line-height: 1;
          border-radius: 4px;
        `,
        onclick: close,
        title: 'Close (Escape)'
      }, ['\u00d7']);

      // Hover effect
      closeBtn.onmouseover = () => { closeBtn.style.background = '#f0f0f0'; };
      closeBtn.onmouseout = () => { closeBtn.style.background = 'transparent'; };

      header.appendChild(closeBtn);
    }

    modalBox.appendChild(header);
  }

  // Content container
  const contentContainer = createElement('div', {
    style: 'padding: 20px; overflow: auto; flex: 1;'
  });

  // Add content
  if (typeof content === 'function') {
    const contentEl = content({ close, overlay, modalBox });
    if (contentEl) {
      contentContainer.appendChild(contentEl);
    }
  } else if (content instanceof Node) {
    contentContainer.appendChild(content);
  }

  modalBox.appendChild(contentContainer);
  overlay.appendChild(modalBox);

  // Click backdrop to close
  if (closeOnBackdrop) {
    overlay.onclick = (e) => {
      if (e.target === overlay) {
        close();
      }
    };
  }

  // Stop propagation on modal box
  modalBox.onclick = (e) => {
    e.stopPropagation();
  };

  // Escape key handler
  let escapeHandler = null;
  if (closeOnEscape) {
    escapeHandler = (e) => {
      if (e.key === 'Escape') {
        close();
      }
    };
    document.addEventListener('keydown', escapeHandler);
  }

  // Add to document
  document.body.appendChild(overlay);

  return { close, overlay, modalBox, contentContainer };
}

/**
 * Shows a confirmation dialog.
 * @param {Object} options - Confirmation options
 * @param {string} options.message - Message to display
 * @param {string} [options.title='Confirm'] - Dialog title
 * @param {string} [options.confirmText='OK'] - Confirm button text
 * @param {string} [options.cancelText='Cancel'] - Cancel button text
 * @param {string} [options.confirmStyle='primary'] - Confirm button style: 'primary', 'danger'
 * @param {Object} [options.api] - Hobson API
 * @returns {Promise<boolean>} - true if confirmed, false if cancelled
 */
export function confirm(options = {}) {
  const {
    message,
    title = 'Confirm',
    confirmText = 'OK',
    cancelText = 'Cancel',
    confirmStyle = 'primary',
    api
  } = options;

  return new Promise((resolve) => {
    const confirmBtnColor = confirmStyle === 'danger' ? '#dc3545' : '#007bff';

    const { close } = showModal({
      title,
      width: '400px',
      api,
      onClose: () => resolve(false),
      content: ({ close: closeModal }) => {
        const container = document.createElement('div');

        // Message
        const messageEl = document.createElement('p');
        messageEl.textContent = message;
        messageEl.style.cssText = 'margin: 0 0 20px 0; font-size: 14px; color: #333; line-height: 1.5;';
        container.appendChild(messageEl);

        // Buttons
        const buttonRow = document.createElement('div');
        buttonRow.style.cssText = 'display: flex; gap: 10px; justify-content: flex-end;';

        const cancelBtn = document.createElement('button');
        cancelBtn.textContent = cancelText;
        cancelBtn.style.cssText = 'padding: 8px 16px; cursor: pointer; border: 1px solid #ccc; background: white; border-radius: 4px;';
        cancelBtn.onclick = () => {
          resolve(false);
          closeModal();
        };
        buttonRow.appendChild(cancelBtn);

        const confirmBtn = document.createElement('button');
        confirmBtn.textContent = confirmText;
        confirmBtn.style.cssText = `padding: 8px 16px; cursor: pointer; border: none; background: ${confirmBtnColor}; color: white; border-radius: 4px;`;
        confirmBtn.onclick = () => {
          resolve(true);
          closeModal();
        };
        buttonRow.appendChild(confirmBtn);

        container.appendChild(buttonRow);
        return container;
      }
    });
  });
}

/**
 * Shows an alert dialog.
 * @param {Object} options - Alert options
 * @param {string} options.message - Message to display
 * @param {string} [options.title='Alert'] - Dialog title
 * @param {string} [options.buttonText='OK'] - Button text
 * @param {Object} [options.api] - Hobson API
 * @returns {Promise<void>}
 */
export function alert(options = {}) {
  const {
