export function render(value, options, api) {
  const { level = 1, mode, onChange } = options;

  // Clamp level to 1-6
  const headingLevel = Math.max(1, Math.min(6, level));
  const tag = 'h' + headingLevel;

  const wrapper = api.createElement('div', { className: 'field-heading' });
  wrapper.style.cssText = 'margin-bottom: 8px;';

  if (mode === 'editable' && onChange) {
    // Editable mode: use contenteditable or input styled as heading
    const input = api.createElement('input', {
      type: 'text',
      style: 'width: 100%; border: none; border-bottom: 2px solid #ddd; background: transparent; outline: none; font-weight: bold; padding: 4px 0;'
    });

    // Set font size based on level
    const sizes = { 1: '28px', 2: '24px', 3: '20px', 4: '18px', 5: '16px', 6: '14px' };
    input.style.fontSize = sizes[headingLevel];

    input.value = value || '';
    input.placeholder = 'Enter title...';
    input.oninput = (e) => onChange(e.target.value);
    wrapper.appendChild(input);
  } else {
    // Readonly mode: render as actual heading element
    const heading = api.createElement(tag);
    heading.textContent = value || '';
    heading.style.cssText = 'margin: 0; font-weight: bold;';
    wrapper.appendChild(heading);
  }

  return wrapper;
}

export function render(value, options, api) {
  const { mode, onChange, label } = options;
  const wrapper = api.createElement('div', { className: 'field-json' });
  wrapper.style.cssText = 'display: flex; flex-direction: column; gap: 4px;';

  if (label) {
    const labelEl = api.createElement('label');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-weight: 500; font-size: 14px; color: #333;';
    wrapper.appendChild(labelEl);
  }

  const jsonStr = JSON.stringify(value, null, 2);

  if (mode === 'editable' && onChange) {
    const textarea = api.createElement('textarea', { style: 'padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 13px; font-family: monospace; resize: vertical; min-height: 100px;' });
    textarea.value = jsonStr;
    const errorEl = api.createElement('div');
    errorEl.style.cssText = 'color: #dc3545; font-size: 12px; min-height: 16px;';
    textarea.oninput = (e) => {
      try {
        onChange(JSON.parse(e.target.value));
        errorEl.textContent = '';
        textarea.style.borderColor = '#ccc';
      } catch (err) {
        errorEl.textContent = 'Invalid JSON';
        textarea.style.borderColor = '#dc3545';
      }
    };
    wrapper.appendChild(textarea);
    wrapper.appendChild(errorEl);
  } else {
    const pre = api.createElement('pre');
    pre.textContent = jsonStr;
    pre.style.cssText = 'padding: 8px; background: #f5f5f5; border-radius: 4px; font-size: 13px; font-family: monospace; white-space: pre-wrap; margin: 0;';
    wrapper.appendChild(pre);
  }
  return wrapper;
}

// Helper: Find the line number where a region starts
function findRegionStartLine(text, regionName) {
  const lines = text.split('\n');
  const marker = '[BEGIN:' + regionName + ']';
  for (let i = 0; i < lines.length; i++) {
    const cleaned = lines[i].trim()
      .replace(/^\/\/\s*/, '')
      .replace(/^#\s*/, '')
      .replace(/^<!--\s*/, '')
      .replace(/\s*-->$/, '')
      .trim();
    if (cleaned === marker) return i + 2; // Line after marker (1-indexed)
  }
  return null;
}

// Markdown editable field view
// Supports sizing option: "compact" (default) or "fill"
export async function render(value, options, api) {
  const { onChange, label, placeholder, sizing, scrollToLine, scrollToRegion } = options;
  const markdown = value || '';
  const isFill = sizing === 'fill';

  const wrapper = api.createElement('div', { className: 'field-markdown-editable' });
  // For fill mode, wrapper needs flex: 1 and min-height: 0 to allow shrinking
  wrapper.style.cssText = isFill
    ? 'display: flex; flex-direction: column; gap: 8px; flex: 1; min-height: 0;'
    : 'display: flex; flex-direction: column; gap: 8px;';

  if (label) {
    const labelEl = api.createElement('label');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-weight: 500; font-size: 14px; color: #333; flex-shrink: 0;';
    wrapper.appendChild(labelEl);
  }

  // Load CSS and CodeMirror
  const cssLoader = await api.require('css-loader-lib');
  await cssLoader.loadCSS('codemirror-css', api);
  await api.require('codemirror');
  await api.require('codemirror-markdown');
  const CodeMirror = window.CodeMirror;

  // Editor container - sizing depends on mode
  const editorContainer = api.createElement('div');
  editorContainer.style.cssText = isFill
    ? 'border: 1px solid #d0d0d0; border-radius: 6px; overflow: hidden; flex: 1; min-height: 150px;'
    : 'border: 1px solid #d0d0d0; border-radius: 6px; overflow: hidden; min-height: 120px; height: 150px; resize: vertical;';
  wrapper.appendChild(editorContainer);

  // Create CodeMirror instance
  const cm = CodeMirror(editorContainer, {
    value: markdown,
    mode: 'markdown',
    lineNumbers: true,
    lineWrapping: true,
    theme: 'default',
    viewportMargin: Infinity,
    placeholder: placeholder || '',
    extraKeys: {
      'Tab': (editor) => editor.replaceSelection('  ')
    }
  });

  cm.setSize('100%', '100%');

  // Function to handle line/region navigation
  const navigateToTarget = () => {
    let targetLine = scrollToLine;

    // If scrollToRegion is specified but no line, find the region
    if (scrollToRegion && !targetLine) {
      targetLine = findRegionStartLine(markdown, scrollToRegion);
    }

    if (targetLine) {
      // CodeMirror uses 0-based line numbers
      const cmLine = targetLine - 1;

      // Scroll line into view and set cursor
      cm.scrollIntoView({ line: cmLine, ch: 0 }, 100);
      cm.setCursor({ line: cmLine, ch: 0 });
      cm.focus();

      // Add highlight class to the line
      cm.addLineClass(cmLine, 'background', 'line-highlight');

      // Add CSS for highlight if not present
      if (!document.getElementById('line-highlight-css')) {
        const style = document.createElement('style');
        style.id = 'line-highlight-css';
        style.textContent = '.line-highlight { background: #fff3cd !important; }';
        document.head.appendChild(style);
      }
    }
  };

  // Refresh CodeMirror when container is resized
  const resizeObserver = new ResizeObserver(() => cm.refresh());
  resizeObserver.observe(editorContainer);

  // Use IntersectionObserver to refresh CodeMirror when visible and navigate
  const observer = new IntersectionObserver((entries) => {
    for (const entry of entries) {
      if (entry.isIntersecting) {
        cm.refresh();
        navigateToTarget();
        observer.disconnect();
        break;
      }
    }
  }, { threshold: 0.1 });
  observer.observe(editorContainer);

  // Also refresh after layout completes to fix gutter width calculation
  requestAnimationFrame(() => cm.refresh());

  // Call onChange on edits
  if (onChange) {
    cm.on('change', () => {
      onChange(cm.getValue());
    });
  }

  // Insert link/transclusion button
  const insertBtn = api.createElement('button');
  insertBtn.textContent = 'Insert Link/Transclusion';
  insertBtn.style.cssText = 'padding: 8px 16px; background: #28a745; color: white; border: none; border-radius: 4px; cursor: pointer; align-self: flex-start; flex-shrink: 0;';
  wrapper.appendChild(insertBtn);

  // Picker container (hidden initially)
  const pickerContainer = api.createElement('div');
  pickerContainer.style.cssText = 'display: none; padding: 15px; border: 1px solid #ddd; border-radius: 6px; background: #f9f9f9; flex-shrink: 0;';
  wrapper.appendChild(pickerContainer);

  insertBtn.onclick = async () => {
    pickerContainer.innerHTML = '';
    pickerContainer.style.display = 'block';

    const header = api.createElement('div');
    header.style.cssText = 'display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;';

    const title = api.createElement('h4');
    title.style.cssText = 'margin: 0;';
    title.textContent = 'Insert Link or Transclusion';
    header.appendChild(title);

    const closeBtn = api.createElement('button');
    closeBtn.textContent = 'Close';
    closeBtn.style.cssText = 'padding: 6px 12px; cursor: pointer; background: #f0f0f0; border: 1px solid #ccc; border-radius: 4px;';
    closeBtn.onclick = () => {
      pickerContainer.style.display = 'none';
      pickerContainer.innerHTML = '';
    };
    header.appendChild(closeBtn);
    pickerContainer.appendChild(header);

    const searchContainer = api.createElement('div');
    pickerContainer.appendChild(searchContainer);

    const searchLib = await api.require('item-search-lib');

    const insertReference = (targetItem, asTransclusion) => {
      const targetName = targetItem.name || targetItem.id;
      const prefix = asTransclusion ? '!' : '';
      const refText = prefix + '[' + targetName + '](item://' + targetItem.id + ')';
      cm.replaceSelection(refText);
      pickerContainer.style.display = 'none';
      pickerContainer.innerHTML = '';
      cm.focus();
    };

    const onSelectCallback = (targetItem) => {
      const existing = searchContainer.querySelector('.item-action-buttons');
      if (existing) existing.remove();

      const actionButtons = api.createElement('div', { className: 'item-action-buttons' });
      actionButtons.style.cssText = 'margin-top: 15px; padding: 15px; background: #fff; border: 1px solid #ddd; border-radius: 4px; display: flex; gap: 10px; align-items: center;';

      const selectedLabel = api.createElement('div');
      selectedLabel.style.cssText = 'flex: 1; font-weight: 500;';
      selectedLabel.textContent = 'Selected: ' + (targetItem.name || targetItem.id);
      actionButtons.appendChild(selectedLabel);

      const linkBtn = api.createElement('button');
      linkBtn.textContent = 'Insert Link';
      linkBtn.style.cssText = 'padding: 8px 16px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px;';
      linkBtn.onclick = () => insertReference(targetItem, false);
      actionButtons.appendChild(linkBtn);

      const transcludeBtn = api.createElement('button');
      transcludeBtn.textContent = 'Insert Transclusion';
      transcludeBtn.style.cssText = 'padding: 8px 16px; cursor: pointer; background: #28a745; color: white; border: none; border-radius: 4px;';
      transcludeBtn.onclick = () => insertReference(targetItem, true);
      actionButtons.appendChild(transcludeBtn);

      searchContainer.appendChild(actionButtons);
    };

    searchLib.createSearchUI(searchContainer, onSelectCallback, api, {
      placeholder: 'Search items...',
      autoFocus: true
    });
  };

  return wrapper;
}

/**
 * Search items based on query string
 */
export async function searchItems(query, api, options = {}) {
  if (!query || query.trim().length === 0) {
    return [];
  }

  const { targetContainer, allItems } = options;
  let itemsToSearch;

  if (allItems) {
    itemsToSearch = allItems;
  } else if (targetContainer) {
    try {
      const container = await api.get(targetContainer);
      const childIds = (container.children || []).map(c =>
        typeof c === 'string' ? c : c.id
      );
      itemsToSearch = await Promise.all(
        childIds.map(id => api.get(id).catch(() => null))
      );
      itemsToSearch = itemsToSearch.filter(i => i !== null);
    } catch (err) {
      console.error('Error fetching container:', err);
      itemsToSearch = [];
    }
  } else {
    itemsToSearch = await api.getAll();
  }

  const queryLower = query.toLowerCase();
  const matches = itemsToSearch.filter(item => {
    const searchableText = [
      item.id,
      item.type,
      item.name,
      item.content?.title,
      item.content?.body,
      item.content?.description,
      JSON.stringify(item.content)
    ].filter(Boolean).join(' ').toLowerCase();

    return searchableText.includes(queryLower);
  });

  matches.sort((a, b) => a.name.localeCompare(b.name));
  return matches;
}

/**
 * Create a search UI widget
 */
export function createSearchUI(containerEl, onSelect, api, options = {}) {
  const {
    placeholder = 'Search for items...',
    savedQuery = '',
    targetContainer = null,
    autoFocus = false
  } = options;

  containerEl.innerHTML = '';

  const searchBox = api.createElement('div', {
    style: 'margin-bottom: 20px;'
  }, []);

  const input = api.createElement('input', {
    type: 'text',
    placeholder,
    value: savedQuery,
    style: 'width: 100%; padding: 12px 16px; font-size: 16px; border: 2px solid #d0d0d0; border-radius: 8px; outline: none; transition: border-color 0.2s;'
  }, []);

  input.onfocus = () => { input.style.borderColor = '#3b82f6'; };
  input.onblur = () => { input.style.borderColor = '#d0d0d0'; };

  searchBox.appendChild(input);
  containerEl.appendChild(searchBox);

  const resultsContainer = api.createElement('div', {}, []);
  containerEl.appendChild(resultsContainer);

  const statusDiv = api.createElement('div', {
    style: 'padding: 40px; text-align: center; color: #999; font-style: italic;'
  }, ['Type to search...']);
  resultsContainer.appendChild(statusDiv);

  const resultsList = api.createElement('div', {
    style: 'display: none; max-height: 600px; overflow-y: auto;'
  }, []);
  resultsContainer.appendChild(resultsList);

  let searchTimeout = null;
  let currentQuery = savedQuery;

  const executeSearch = async (query) => {
    currentQuery = query;

    if (!query || query.trim().length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.textContent = 'Type to search...';
      return;
    }

    statusDiv.style.display = 'block';
    resultsList.style.display = 'none';
    statusDiv.textContent = 'Searching...';

    const matches = await searchItems(query, api, { targetContainer });

    if (matches.length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.innerHTML = '';

      // Message
      const noMatchMsg = api.createElement('div', {
        style: 'margin-bottom: 16px;'
      }, ['No items found matching "' + query + '"']);
      statusDiv.appendChild(noMatchMsg);

      // Create New button
      const createBtn = api.createElement('button', {
        style: 'padding: 10px 20px; background: #3b82f6; color: white; border: none; border-radius: 6px; cursor: pointer; font-size: 14px; font-weight: 500; transition: background 0.2s;',
        onclick: async () => {
          try {
            // Look up note type
            const noteTypes = await api.query({ name: 'note' });
            const noteTypeId = noteTypes[0]?.id || '871ae771-b9b1-4f40-8c7f-d9038bfb69c3';

            // Create sanitized name (lowercase, underscores for spaces)
            const sanitizedName = query.toLowerCase().replace(/\s+/g, '_');

            // Create new note item
            const newItem = {
              id: crypto.randomUUID(),
              name: sanitizedName,
              type: noteTypeId,
              created: Date.now(),
              modified: Date.now(),
              children: [],
              content: {
                title: query,
                description: ''
              }
            };

            // Save and select
            await api.set(newItem);
            onSelect(newItem);
          } catch (err) {
            console.error('Failed to create item:', err);
            alert('Failed to create item: ' + err.message);
          }
        }
      }, ['Create New: ' + query]);

      // Hover effects
      createBtn.onmouseover = () => {
        createBtn.style.background = '#2563eb';
      };
      createBtn.onmouseout = () => {
        createBtn.style.background = '#3b82f6';
      };

      statusDiv.appendChild(createBtn);
    } else {
      statusDiv.style.display = 'none';
      resultsList.style.display = 'block';
      resultsList.innerHTML = '';

      const countHeader = api.createElement('div', {
        style: 'margin-bottom: 15px; font-size: 14px; color: #666; font-weight: 500;'
      }, ['Found ' + matches.length + ' item' + (matches.length === 1 ? '' : 's')]);
      resultsList.appendChild(countHeader);

      matches.forEach(item => {
        const resultDiv = api.createElement('div', {
          style: 'padding: 12px; margin-bottom: 8px; background: white; border: 1px solid #ddd; border-radius: 6px; cursor: pointer; transition: all 0.2s;'
        }, []);

        const itemTitle = api.createElement('div', {
          style: 'font-weight: 500; color: #333; margin-bottom: 6px; font-size: 15px;'
        }, [item.name || item.content?.title || item.id]);
        resultDiv.appendChild(itemTitle);

        const previewText = item.content?.body || item.content?.description ||
                           JSON.stringify(item.content).substring(0, 150);
        const preview = api.createElement('div', {
          style: 'font-size: 13px; color: #666; margin-bottom: 6px; line-height: 1.4; overflow: hidden; text-overflow: ellipsis; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical;'
        }, [previewText.substring(0, 200)]);
        resultDiv.appendChild(preview);

        const meta = api.createElement('div', {
          style: 'font-size: 12px; color: #999;'
        }, [
          'Type: ' + item.type.substring(0, 8) + '... | Modified: ' +
          new Date(item.modified).toLocaleDateString()
        ]);
        resultDiv.appendChild(meta);

        resultDiv.onclick = () => { onSelect(item); };

        resultDiv.onmouseover = () => {
          resultDiv.style.background = '#f8f9fa';
          resultDiv.style.borderColor = '#3b82f6';
          resultDiv.style.transform = 'translateX(4px)';
        };
        resultDiv.onmouseout = () => {
          resultDiv.style.background = 'white';
          resultDiv.style.borderColor = '#ddd';
          resultDiv.style.transform = 'translateX(0)';
        };

        resultsList.appendChild(resultDiv);
      });
    }
  };

  const performSearch = (query) => {
    if (searchTimeout) {
      clearTimeout(searchTimeout);
    }
    searchTimeout = setTimeout(() => {
      executeSearch(query);
    }, 300);
  };

  input.oninput = (e) => {
    performSearch(e.target.value);
  };

  if (autoFocus) {
    setTimeout(() => input.focus(), 0);
  }

  if (savedQuery && savedQuery.trim().length > 0) {
    executeSearch(savedQuery);
  }

  return {
    performSearch: executeSearch,
    getQuery: () => currentQuery,
    setQuery: (query) => {
      input.value = query;
      executeSearch(query);
    },
    destroy: () => {
      if (searchTimeout) {
        clearTimeout(searchTimeout);
      }
      containerEl.innerHTML = '';
    }
  };
}

// Sortable List View - Phases 1-3: Display, Item Picker, Drag-and-Drop

const COMPACT_CARD_VIEW_ID = 'd4e5f6a7-b8c9-4d0e-a1b2-c3d4e5f6a7b8';

export async function render(item, api) {
  const container = api.createElement('div', {
    class: 'sortable-list-view',
    style: 'display: flex; flex-direction: column; height: 100%; background: #fafafa;'
  }, []);

  // List container (created first so header can reference it)
  const listContainer = api.createElement('div', {
    class: 'sortable-list-items',
    style: 'flex: 1; overflow-y: auto; padding: 16px;'
  }, []);

  // Header section
  const header = createHeader(item, api, listContainer);
  container.appendChild(header);
  container.appendChild(listContainer);

  // Initial render
  await renderChildren(listContainer, item, api);

  return container;
}

function createHeader(item, api, listContainer) {
  const header = api.createElement('div', {
    style: 'padding: 16px; border-bottom: 2px solid #e0e0e0; background: white;'
  }, []);

  const titleRow = api.createElement('div', {
    style: 'display: flex; justify-content: space-between; align-items: center;'
  }, []);

  const title = api.createElement('h2', {
    style: 'margin: 0; font-size: 20px;'
  }, [item.name || 'Untitled List']);

  //const addButton = api.createElement('button', {
  //  style: 'padding: 8px 16px; background: #3498db; color: white; border: none; border-radius: 4px; cursor: pointer; font-size: 14px;',
  //  onclick: () => showItemPicker(item, api, listContainer)
  //}, ['+ Add Item']);
  //addButton.onmouseover = () => { addButton.style.background = '#2980b9'; };
  //addButton.onmouseout = () => { addButton.style.background = '#3498db'; };

  titleRow.appendChild(title);
  //titleRow.appendChild(addButton);
  header.appendChild(titleRow);

  return header;
}

async function renderChildren(listContainer, parentItem, api) {
  listContainer.innerHTML = '';
  const children = parentItem.children || [];

  if (children.length === 0) {
    const empty = api.createElement('div', {
      style: 'text-align: center; color: #999; padding: 60px 20px; font-style: italic;'
    }, ['This list is empty. Click "+ Add Item" to add items.']);
    listContainer.appendChild(empty);
    return;
  }

  const compactViews = await api.query({ name: 'compact-card-view' });
  const defaultViewId = compactViews[0]?.id || COMPACT_CARD_VIEW_ID;

  for (let i = 0; i < children.length; i++) {
    const childSpec = children[i];
    const childId = typeof childSpec === 'string' ? childSpec : childSpec.id;
    const childViewId = typeof childSpec === 'string' ? defaultViewId : (childSpec.view?.type || defaultViewId);

    const childItem = await api.get(childId);
    if (!childItem) continue;

    const listItem = await createListItem(childId, i, childViewId, parentItem, api, listContainer);
    listContainer.appendChild(listItem);
  }

  // Setup drag-and-drop
  setupDragAndDrop(listContainer, parentItem, api);
}

async function createListItem(childId, index, viewId, parentItem, api, listContainer) {
  const listItem = api.createElement('div', {
    'data-item-id': childId,
    'data-parent-id': parentItem.id,
    'data-index': index,
    class: 'sortable-list-item',
    style: 'display: flex; align-items: stretch; background: white; border: 1px solid #ddd; border-radius: 4px; margin-bottom: 8px; overflow: hidden;'
  }, []);

  const dragHandle = api.createElement('div', {
    class: 'drag-handle',
    style: 'width: 32px; background: #f5f5f5; border-right: 1px solid #ddd; display: flex; align-items: center; justify-content: center; cursor: grab; user-select: none; flex-shrink: 0; color: #999;',
    title: 'Drag to reorder'
  }, ['\u2261']);
  dragHandle.onmouseover = () => { dragHandle.style.background = '#e8e8e8'; };
  dragHandle.onmouseout = () => { dragHandle.style.background = '#f5f5f5'; };

  const contentArea = api.createElement('div', {
    style: 'flex: 1; padding: 12px; min-width: 0;'
  }, []);

  try {
    const childNode = await api.renderItem(childId, viewId);
    contentArea.appendChild(childNode);
  } catch (error) {
    const errorMsg = api.createElement('div', {
      style: 'color: #c00; font-style: italic;'
    }, ['Error rendering item']);
    contentArea.appendChild(errorMsg);
  }

  const actions = api.createElement('div', {
    style: 'width: 32px; border-left: 1px solid #ddd; display: flex; align-items: center; justify-content: center; flex-shrink: 0;'
  }, []);

  const removeButton = api.createElement('button', {
    style: 'background: none; border: none; color: #999; cursor: pointer; font-size: 18px; padding: 4px;',
    onclick: async (e) => {
      e.stopPropagation();
      await removeItemFromList(parentItem, childId, api, listContainer);
    },
    title: 'Remove from list'
  }, ['\u00d7']);
  removeButton.onmouseover = () => { removeButton.style.color = '#c00'; };
  removeButton.onmouseout = () => { removeButton.style.color = '#999'; };

  actions.appendChild(removeButton);
  listItem.appendChild(dragHandle);
  listItem.appendChild(contentArea);
  listItem.appendChild(actions);

  return listItem;
}

// Phase 2: Item Picker
async function showItemPicker(parentItem, api, listContainer) {
  const overlay = api.createElement('div', {
    style: 'position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.5); display: flex; align-items: center; justify-content: center; z-index: 10000;'
  }, []);

  const modal = api.createElement('div', {
    style: 'background: white; border-radius: 8px; width: 90%; max-width: 600px; max-height: 80vh; display: flex; flex-direction: column; box-shadow: 0 4px 20px rgba(0,0,0,0.3);'
  }, []);

  const modalHeader = api.createElement('div', {
    style: 'display: flex; justify-content: space-between; align-items: center; padding: 20px; border-bottom: 1px solid #ddd;'
  }, []);

  const modalTitle = api.createElement('h3', { style: 'margin: 0;' }, ['Add Item to List']);

  const closeBtn = api.createElement('button', {
    style: 'padding: 4px 10px; cursor: pointer; background: transparent; border: none; font-size: 24px; color: #666;',
    onclick: () => document.body.removeChild(overlay)
  }, ['\u00d7']);

  modalHeader.appendChild(modalTitle);
  modalHeader.appendChild(closeBtn);
  modal.appendChild(modalHeader);

  const searchContainer = api.createElement('div', {
    style: 'padding: 20px; flex: 1; overflow: auto;'
  }, []);
  modal.appendChild(searchContainer);

  overlay.appendChild(modal);
  document.body.appendChild(overlay);

  const searchLib = await api.require('item-search-lib');

  const existingIds = new Set(
    (parentItem.children || []).map(c => typeof c === 'string' ? c : c.id)
  );
  existingIds.add(parentItem.id);

  searchLib.createSearchUI(
    searchContainer,
    async (selectedItem) => {
      if (existingIds.has(selectedItem.id)) {
        alert('This item is already in the list.');
        return;
      }
      await addItemToList(parentItem, selectedItem.id, api, listContainer);
      document.body.removeChild(overlay);
    },
    api,
    { placeholder: 'Search for items to add...', autoFocus: true }
  );

  overlay.onclick = (e) => {
    if (e.target === overlay) document.body.removeChild(overlay);
  };
  modal.onclick = (e) => e.stopPropagation();
}

async function addItemToList(parentItem, itemId, api, listContainer) {
  const fresh = await api.get(parentItem.id);
  const children = (fresh.children || []).map(c => typeof c === 'string' ? { id: c } : c);
  children.push({ id: itemId });

  const updated = { ...fresh, children, modified: Date.now() };
  await api.set(updated);
  parentItem.children = updated.children;

  // Re-render list
  await renderChildren(listContainer, parentItem, api);
}

async function removeItemFromList(parentItem, childId, api, listContainer) {
  const fresh = await api.get(parentItem.id);
  const children = (fresh.children || []).filter(c => {
    const id = typeof c === 'string' ? c : c.id;
    return id !== childId;
  });

  const updated = { ...fresh, children, modified: Date.now() };
  await api.set(updated);
  parentItem.children = updated.children;

  const itemElement = listContainer.querySelector(`[data-item-id="${childId}"]`);
  if (itemElement) itemElement.remove();

  listContainer.querySelectorAll('.sortable-list-item').forEach((el, i) => {
    el.setAttribute('data-index', i);
  });

  if (children.length === 0) {
    listContainer.innerHTML = '';
    const empty = api.createElement('div', {
      style: 'text-align: center; color: #999; padding: 60px 20px; font-style: italic;'
    }, ['This list is empty. Click "+ Add Item" to add items.']);
    listContainer.appendChild(empty);
  }
}

// Phase 3: Drag-and-Drop
function setupDragAndDrop(listContainer, parentItem, api) {
  let draggedItem = null;
  let draggedIndex = null;
  let dropIndicator = null;

  dropIndicator = api.createElement('div', {
    class: 'drop-indicator',
    style: 'height: 3px; background: #3498db; margin: 4px 0; border-radius: 2px; display: none;'
  }, []);

  const items = listContainer.querySelectorAll('.sortable-list-item');

  items.forEach((item, index) => {
    const dragHandle = item.querySelector('.drag-handle');

    dragHandle.onmousedown = (e) => {
      e.preventDefault();
      draggedItem = item;
      draggedIndex = parseInt(item.getAttribute('data-index'), 10);

      item.style.opacity = '0.5';
      dragHandle.style.cursor = 'grabbing';

      item.parentNode.insertBefore(dropIndicator, item.nextSibling);

      document.onmousemove = handleDrag;
      document.onmouseup = endDrag;
    };
  });

  function handleDrag(e) {
    if (!draggedItem) return;

    const items = Array.from(listContainer.querySelectorAll('.sortable-list-item'));
    const mouseY = e.clientY;
    let targetIndex = items.length;

    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      if (item === draggedItem) continue;
      const rect = item.getBoundingClientRect();
      if (mouseY < rect.top + rect.height / 2) {
        targetIndex = i;
        break;
      }
    }

    dropIndicator.style.display = 'block';

    if (targetIndex < items.length) {
      listContainer.insertBefore(dropIndicator, items[targetIndex]);
    } else {
      listContainer.appendChild(dropIndicator);
    }
  }

  async function endDrag(e) {
    if (!draggedItem) return;

    const items = Array.from(listContainer.querySelectorAll('.sortable-list-item'));
    const mouseY = e.clientY;
    let newIndex = items.length;  // Position after last item

    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      if (item === draggedItem) continue;
      const rect = item.getBoundingClientRect();
      if (mouseY < rect.top + rect.height / 2) {
        newIndex = i;
        break;
      }
    }

    // Adjust for the dragged item being removed before insertion
    if (newIndex > draggedIndex) newIndex--;

    if (newIndex !== draggedIndex) {
      await updateChildOrder(parentItem, draggedIndex, newIndex, api, listContainer);
    }

    draggedItem.style.opacity = '1';
    draggedItem.querySelector('.drag-handle').style.cursor = 'grab';
    dropIndicator.style.display = 'none';
    if (dropIndicator.parentNode) dropIndicator.parentNode.removeChild(dropIndicator);

    draggedItem = null;
    draggedIndex = null;
    document.onmousemove = null;
    document.onmouseup = null;
  }
}

async function updateChildOrder(parentItem, fromIndex, toIndex, api, listContainer) {
  const fresh = await api.get(parentItem.id);
  let children = (fresh.children || []).map(c => typeof c === 'string' ? { id: c } : c);

  const [movedItem] = children.splice(fromIndex, 1);
  children.splice(toIndex, 0, movedItem);

  const updated = { ...fresh, children, modified: Date.now() };
  await api.set(updated);
  parentItem.children = updated.children;

  // Move element in DOM
  const items = Array.from(listContainer.querySelectorAll('.sortable-list-item'));
  const movedElement = items[fromIndex];

  if (toIndex >= items.length - 1) {
    listContainer.appendChild(movedElement);
  } else {
    const targetElement = toIndex > fromIndex ? items[toIndex + 1] : items[toIndex];
    listContainer.insertBefore(movedElement, targetElement);
  }

  listContainer.querySelectorAll('.sortable-list-item').forEach((el, i) => {
    el.setAttribute('data-index', i);
  });
}

export function render(value, options, api) {
  const { mode, onChange, label } = options;
  const wrapper = api.createElement('div', { className: 'field-checkbox' });
  wrapper.style.cssText = 'display: flex; align-items: center; gap: 8px;';

  if (mode === 'editable' && onChange) {
    const input = api.createElement('input', { type: 'checkbox', style: 'width: 18px; height: 18px; cursor: pointer;' });
    input.checked = !!value;
    input.onchange = (e) => onChange(e.target.checked);
    wrapper.appendChild(input);
  } else {
    const indicator = api.createElement('span');
    indicator.textContent = value ? '\u2713' : '\u2717';
    indicator.style.cssText = 'font-size: 18px; color: ' + (value ? '#28a745' : '#dc3545') + ';';
    wrapper.appendChild(indicator);
  }

  if (label) {
    const labelEl = api.createElement('label');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-size: 14px; color: #333;';
    wrapper.appendChild(labelEl);
  }
  return wrapper;
}

// Script code field view (readonly with run/copy buttons)
export async function render(value, options, api) {
  const { label, language = 'javascript' } = options;
  const code = value || '';

  const wrapper = api.createElement('div', { className: 'field-script-code' });
  wrapper.style.cssText = 'display: flex; flex-direction: column; gap: 12px;';

  if (label) {
    const labelEl = api.createElement('label');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-weight: 500; font-size: 14px; color: #333;';
    wrapper.appendChild(labelEl);
  }

  // Load CSS and CodeMirror
  const cssLoader = await api.require('css-loader-lib');
  await cssLoader.loadCSS('codemirror-css', api);
  await api.require('codemirror');
  await api.require('codemirror-javascript');
  const CodeMirror = window.CodeMirror;

  // Editor container
  const editorContainer = api.createElement('div');
  editorContainer.style.cssText = 'border: 1px solid #d0d0d0; border-radius: 6px; overflow: hidden;';
  wrapper.appendChild(editorContainer);

  // Create CodeMirror instance in readonly mode
  const cm = CodeMirror(editorContainer, {
    value: code,
    mode: language,
    lineNumbers: true,
    lineWrapping: true,
    theme: 'default',
    readOnly: true,
    cursorBlinkRate: -1,
    viewportMargin: 2000
  });

  cm.setSize('100%', '300px');

  // Refresh after layout
  requestAnimationFrame(() => cm.refresh());

  // Action buttons
  const buttons = api.createElement('div');
  buttons.style.cssText = 'display: flex; gap: 10px;';

  // Run Script button
  const runBtn = api.createElement('button');
  runBtn.textContent = 'Run Script';
  runBtn.style.cssText = 'padding: 10px 20px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px; font-weight: 500;';
  runBtn.onclick = async () => {
    runBtn.disabled = true;
    runBtn.textContent = 'Running...';

    try {
      // Get the REPL API which has the helper functions
      const replApi = api.createREPLContext();

      // Execute the script code with REPL API
      const asyncFn = new Function('api', `
        return (async () => {
          ${code}
        })();
      `);

      const result = await asyncFn(replApi);
      alert('Script executed!\n\nResult: ' + (
        result !== undefined
          ? JSON.stringify(result, null, 2)
          : 'No return value'
      ));
    } catch (error) {
      alert('Error executing script:\n\n' + error.message);
    } finally {
      runBtn.disabled = false;
      runBtn.textContent = 'Run Script';
    }
  };
  buttons.appendChild(runBtn);

  // Copy Code button
  const copyBtn = api.createElement('button');
  copyBtn.textContent = 'Copy Code';
  copyBtn.style.cssText = 'padding: 10px 20px; cursor: pointer; border: 1px solid #ccc; border-radius: 4px; background: white;';
  copyBtn.onclick = () => {
    navigator.clipboard.writeText(code);
    copyBtn.textContent = 'Copied!';
    setTimeout(() => { copyBtn.textContent = 'Copy Code'; }, 1000);
  };
  buttons.appendChild(copyBtn);

  wrapper.appendChild(buttons);

  return wrapper;
}

export function render(value, onChange, api, options = {}) {
  const textarea = document.createElement('textarea');
  textarea.value = value || '';
  textarea.placeholder = options.placeholder || '';
  textarea.rows = options.rows || 4;
  textarea.style.cssText = 'width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 14px; font-family: inherit; resize: vertical;';

  if (options.readonly) {
    textarea.readOnly = true;
    textarea.style.background = '#f5f5f5';
  }

  textarea.addEventListener('input', (e) => {
    onChange(e.target.value);
  });

  return textarea;
}

