// Helper: Find the line number where a region starts
function findRegionStartLine(text, regionName) {
  const lines = text.split('\n');
  const marker = '[BEGIN:' + regionName + ']';
  for (let i = 0; i < lines.length; i++) {
    const cleaned = lines[i].trim()
      .replace(/^\/\/\s*/, '')
      .replace(/^#\s*/, '')
      .replace(/^<!--\s*/, '')
      .replace(/\s*-->$/, '')
      .trim();
    if (cleaned === marker) return i + 2; // Line after marker (1-indexed)
  }
  return null;
}

// Code readonly field view (CodeMirror)
export async function render(value, options, api) {
  const { label, language = 'javascript', scrollToLine, scrollToRegion } = options;
  const code = value || '';

  const wrapper = api.createElement('div', { className: 'field-code-readonly' });
  wrapper.style.cssText = 'display: flex; flex-direction: column; gap: 8px;';

  if (label) {
    const labelEl = api.createElement('label');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-weight: 500; font-size: 14px; color: #333;';
    wrapper.appendChild(labelEl);
  }

  // Load CSS and CodeMirror
  const cssLoader = await api.require('css-loader-lib');
  await cssLoader.loadCSS('codemirror-css', api);
  await api.require('codemirror');
  await api.require('codemirror-javascript');
  const CodeMirror = window.CodeMirror;

  // Editor container
  const editorContainer = api.createElement('div');
  editorContainer.style.cssText = 'border: 1px solid #d0d0d0; border-radius: 6px; overflow: hidden;';
  wrapper.appendChild(editorContainer);

  // Create CodeMirror instance in readonly mode
  const cm = CodeMirror(editorContainer, {
    value: code,
    mode: language,
    lineNumbers: true,
    lineWrapping: true,
    theme: 'default',
    readOnly: true,
    cursorBlinkRate: -1,
    viewportMargin: 2000
  });

  cm.setSize('100%', '400px');

  // Process comment spans to make item:// links clickable
  const processCommentLinks = () => {
    const linkRegex = /\[([^\]]+)\]\(item:\/\/([a-f0-9-]+)\)/g;
    const comments = editorContainer.querySelectorAll('.cm-comment:not([data-links-processed])');

    comments.forEach(span => {
      span.setAttribute('data-links-processed', 'true');
      const text = span.textContent;
      if (!linkRegex.test(text)) return;

      // Reset regex state and process
      linkRegex.lastIndex = 0;
      const parts = [];
      let lastIndex = 0;
      let match;

      while ((match = linkRegex.exec(text)) !== null) {
        // Add text before this match
        if (match.index > lastIndex) {
          parts.push(document.createTextNode(text.slice(lastIndex, match.index)));
        }

        // Create clickable link
        const linkText = match[1];
        const itemId = match[2];
        const link = document.createElement('a');
        link.textContent = linkText;
        link.href = '#';
        link.style.cssText = 'color: #007bff; text-decoration: underline; cursor: pointer;';
        link.onclick = (e) => {
          e.preventDefault();
          e.stopPropagation();
          if (api.siblingContainer) {
            api.siblingContainer.addSibling(itemId);
          } else {
            api.navigate(itemId);
          }
        };
        parts.push(link);

        lastIndex = match.index + match[0].length;
      }

      // Add remaining text after last match
      if (lastIndex < text.length) {
        parts.push(document.createTextNode(text.slice(lastIndex)));
      }

      // Replace span contents
      if (parts.length > 0) {
        span.textContent = '';
        parts.forEach(part => span.appendChild(part));
      }
    });
  };

  // Function to handle line/region navigation
  const navigateToTarget = () => {
    // First try options (passed from generic_view), then fall back to URL params
    let targetLine = scrollToLine;
    let col = 0;

    // If scrollToRegion is specified but no line, find the region
    if (scrollToRegion && !targetLine) {
      targetLine = findRegionStartLine(code, scrollToRegion);
    }

    // Fallback to URL params for backward compatibility
    if (!targetLine) {
      const urlParams = new URLSearchParams(window.location.search);
      const urlLine = parseInt(urlParams.get('line'), 10);
      col = parseInt(urlParams.get('col'), 10) || 0;
      if (!isNaN(urlLine) && urlLine > 0) {
        targetLine = urlLine;
      }
    }

    if (targetLine) {
      // CodeMirror uses 0-based line numbers
      const cmLine = targetLine - 1;

      // Scroll line into view
      cm.scrollIntoView({ line: cmLine, ch: col }, 100);

      // Add highlight class to the line
      cm.addLineClass(cmLine, 'background', 'line-highlight');

      // Add CSS for highlight if not present
      if (!document.getElementById('line-highlight-css')) {
        const style = document.createElement('style');
        style.id = 'line-highlight-css';
        style.textContent = '.line-highlight { background: #fff3cd !important; }';
        document.head.appendChild(style);
      }
    }
  };

  // Use IntersectionObserver to refresh CodeMirror when visible
  const observer = new IntersectionObserver((entries) => {
    for (const entry of entries) {
      if (entry.isIntersecting) {
        cm.refresh();
        processCommentLinks();
        navigateToTarget();
        observer.disconnect();
        break;
      }
    }
  }, { threshold: 0.1 });
  observer.observe(editorContainer);

  // Also refresh on first click as fallback
  const clickHandler = () => {
    cm.refresh();
    processCommentLinks();
    navigateToTarget();
    editorContainer.removeEventListener('click', clickHandler);
  };
  editorContainer.addEventListener('click', clickHandler);

  // Re-process links when viewport changes (scroll/resize)
  cm.on('viewportChange', () => {
    requestAnimationFrame(processCommentLinks);
  });

  return wrapper;
}

// Markdown readonly field view
export async function render(value, options, api) {
  const { label, scrollToRegion } = options;
  const markdown = value || '';

  const wrapper = api.createElement('div', { className: 'field-markdown-readonly' });
  wrapper.style.cssText = 'display: flex; flex-direction: column; gap: 4px;';

  if (label) {
    const labelEl = api.createElement('label');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-weight: 500; font-size: 14px; color: #333;';
    wrapper.appendChild(labelEl);
  }

  // Use the hobson-markdown library for rendering
  const hobsonMarkdown = await api.require('hobson-markdown');
  const content = await hobsonMarkdown.render(markdown, api);

  wrapper.appendChild(content);

  // Handle scroll-to-region navigation
  // hobson-markdown emits <span data-region-start="name"> anchors for region markers
  if (scrollToRegion) {
    // Use setTimeout to ensure DOM is ready after append
    setTimeout(() => {
      const anchor = wrapper.querySelector(`[data-region-start="${scrollToRegion}"]`);
      if (anchor) {
        // Find the next visible sibling to scroll to (the anchor itself is display:none)
        let target = anchor.nextElementSibling;
        if (!target) target = anchor.parentElement;
        if (target) {
          target.scrollIntoView({ behavior: 'smooth', block: 'start' });
          // Add brief highlight effect
          target.style.transition = 'background 0.3s';
          target.style.background = '#fff3cd';
          setTimeout(() => {
            target.style.background = '';
          }, 2000);
        }
      }
    }, 100);
  }

  return wrapper;
}

export async function render(search, api) {
  const searchLib = await api.require('item-search-lib');

  const container = api.createElement('div', {
    class: 'item-search-view',
    style: 'max-width: 800px; margin: 0 auto; padding: 20px;'
  }, []);

  // Header
  const header = api.createElement('div', {
    style: 'margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #e0e0e0;'
  }, []);

  const title = api.createElement('h2', {
    style: 'margin: 0; font-size: 20px;'
  }, [search.name || 'Search']);
  header.appendChild(title);
  container.appendChild(header);

  // Search input
  const searchBox = api.createElement('div', {
    style: 'margin-bottom: 20px;'
  }, []);

  const input = api.createElement('input', {
    type: 'text',
    placeholder: 'Search for items...',
    value: search.content?.currentQuery || '',
    style: 'width: 100%; padding: 12px 16px; font-size: 16px; border: 2px solid #d0d0d0; border-radius: 8px; outline: none; transition: border-color 0.2s;'
  }, []);

  input.onfocus = () => { input.style.borderColor = '#3b82f6'; };
  input.onblur = () => { input.style.borderColor = '#d0d0d0'; };

  searchBox.appendChild(input);
  container.appendChild(searchBox);

  // Results area
  const resultsArea = api.createElement('div', {}, []);
  container.appendChild(resultsArea);

  // Find compact_card_view for rendering results (default view)
  const compactViews = await api.query({ name: 'compact-card-view' });
  const compactViewId = compactViews[0]?.id || null;

  // Cycle handler - returns a clickable card for items in render path
  const onCycle = (cycleItem) => {
    const card = api.createElement('div', {
      'data-item-id': cycleItem.id,
      style: 'padding: 12px; margin-bottom: 8px; background: #fffbeb; border: 1px dashed #f59e0b; border-radius: 6px; cursor: pointer; transition: all 0.2s;'
    }, []);

    const titleRow = api.createElement('div', {
      style: 'display: flex; align-items: center; gap: 8px; margin-bottom: 6px;'
    }, []);

    const icon = api.createElement('span', {
      style: 'color: #f59e0b;'
    }, ['↻']);
    titleRow.appendChild(icon);

    const name = api.createElement('span', {
      style: 'font-weight: 500; color: #333;'
    }, [cycleItem.name || cycleItem.id.substring(0, 8)]);
    titleRow.appendChild(name);

    const badge = api.createElement('span', {
      style: 'font-size: 11px; color: #92400e; background: #fef3c7; padding: 2px 6px; border-radius: 4px;'
    }, ['in current view']);
    titleRow.appendChild(badge);

    card.appendChild(titleRow);

    const meta = api.createElement('div', {
      style: 'font-size: 12px; color: #999;'
    }, ['Click to open']);
    card.appendChild(meta);

    card.onmouseover = () => {
      card.style.background = '#fef3c7';
      card.style.borderColor = '#d97706';
      card.style.transform = 'translateX(4px)';
    };
    card.onmouseout = () => {
      card.style.background = '#fffbeb';
      card.style.borderColor = '#f59e0b';
      card.style.transform = 'translateX(0)';
    };

    card.onclick = (e) => {
      e.stopPropagation();
      api.siblingContainer?.addSibling(cycleItem.id);
    };

    return card;
  };

  // Render current results from children
  const renderResults = async () => {
    resultsArea.innerHTML = '';

    const query = search.content?.currentQuery || '';
    const children = search.children || [];

    if (!query || query.trim().length === 0) {
      const emptyMsg = api.createElement('div', {
        style: 'padding: 40px; text-align: center; color: #999; font-style: italic;'
      }, ['Type to search...']);
      resultsArea.appendChild(emptyMsg);
    } else if (children.length === 0) {
      // No results - show create option
      const noResults = api.createElement('div', {
        style: 'text-align: center; padding: 40px;'
      }, []);

      const msg = api.createElement('div', {
        style: 'margin-bottom: 20px; color: #666;'
      }, ['No items found matching "' + query + '"']);
      noResults.appendChild(msg);

      /*
      const createBtn = api.createElement('button', {
        style: 'padding: 10px 20px; background: #3b82f6; color: white; border: none; border-radius: 6px; cursor: pointer; font-size: 14px;',
        onclick: async () => {
          const noteTypes = await api.query({ name: 'note' });
          const noteTypeId = noteTypes[0]?.id || api.IDS.ATOM;

          const newItem = {
            id: crypto.randomUUID(),
            name: query.toLowerCase().replace(/\s+/g, '_'),
            type: noteTypeId,
            created: Date.now(),
            modified: Date.now(),
            children: [],
            content: {
              title: query,
              description: ''
            }
          };

          await api.set(newItem);
          api.openSibling(newItem.id);
        }
      }, ['Create New: ' + query]);

      createBtn.onmouseover = () => { createBtn.style.background = '#2563eb'; };
      createBtn.onmouseout = () => { createBtn.style.background = '#3b82f6'; };

      noResults.appendChild(createBtn); */
      resultsArea.appendChild(noResults);
    } else {
      // Has results - render children with their specified view or compact view
      const countHeader = api.createElement('div', {
        style: 'margin-bottom: 15px; font-size: 14px; color: #666; font-weight: 500;'
      }, ['Found ' + children.length + ' item' + (children.length === 1 ? '' : 's')]);
      resultsArea.appendChild(countHeader);

      const resultsList = api.createElement('div', {}, []);

      for (const childSpec of children) {
        const childId = typeof childSpec === 'string' ? childSpec : childSpec.id;
        // Respect per-child view override (from "Display As..."), fall back to compact view
        const childViewId = (typeof childSpec === 'object' && childSpec.view?.type) ? childSpec.view.type : compactViewId;

        try {
          const childNode = await api.renderItem(childId, childViewId, { onCycle });
          // data-item-id is set automatically by api.renderItem()
          childNode.setAttribute('data-parent-id', search.id);
          resultsList.appendChild(childNode);
        } catch (err) {
          const errorNode = api.createElement('div', {
            style: 'padding: 12px; margin-bottom: 8px; color: #c00; border: 1px solid #fcc; border-radius: 6px; background: #fff5f5;'
          }, ['Error loading item: ' + childId]);
          resultsList.appendChild(errorNode);
        }
      }

      resultsArea.appendChild(resultsList);
    }
  };

  // Initial render of existing results
  await renderResults();

  // Search execution with debouncing
  let searchTimeout = null;

  const executeSearch = async (query) => {
    // Update children with search results
    const targetContainer = search.content?.target_container || null;
    const matches = await searchLib.searchItems(query, api, { targetContainer });

    // Store results as children and save query
    const updated = {
      ...search,
      children: matches.map(m => ({ id: m.id })),
      content: {
        ...search.content,
        currentQuery: query
      }
    };

    await api.set(updated);

    // Update local reference and re-render results
    search.children = updated.children;
    search.content = updated.content;
    await renderResults();
  };

  input.oninput = (e) => {
    const query = e.target.value;

    // Show searching indicator
    if (query && query.trim().length > 0) {
      resultsArea.innerHTML = '';
      const searching = api.createElement('div', {
        style: 'padding: 40px; text-align: center; color: #999; font-style: italic;'
      }, ['Searching...']);
      resultsArea.appendChild(searching);
    }

    // Debounce actual search
    if (searchTimeout) clearTimeout(searchTimeout);
    searchTimeout = setTimeout(() => executeSearch(query), 300);
  };

  // Auto-focus if no query yet
  if (!search.content?.currentQuery) {
    setTimeout(() => input.focus(), 0);
  }

  return container;
}

export function render(value, onChange, api, options = {}) {
  const input = document.createElement('input');
  input.type = 'text';
  input.value = value || '';
  input.placeholder = options.placeholder || '';
  input.style.cssText = 'width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 14px;';

  if (options.readonly) {
    input.readOnly = true;
    input.style.background = '#f5f5f5';
  }

  input.addEventListener('input', (e) => {
    onChange(e.target.value);
  });

  return input;
}

// Tag Tree Builder Library
// Shared logic for building hierarchical tag trees

/**
 * Builds a hierarchical tree structure from a flat list of tag items
 * @param {Array} tags - Flat array of tag items
 * @returns {Array} Root nodes of the tree, each with a children array
 */
export function buildTagTree(tags) {
  // Create map of tags by ID for quick lookup
  const tagMap = new Map();
  tags.forEach(tag => tagMap.set(tag.id, { ...tag, children: [] }));

  // Separate root and child tags
  const roots = [];
  tags.forEach(tag => {
    const parent = tag.content.parent;
    if (!parent) {
      // Root tag (no parent)
      roots.push(tagMap.get(tag.id));
    } else {
      // Child tag - add to parent's children array
      const parentNode = tagMap.get(parent);
      if (parentNode) {
        parentNode.children.push(tagMap.get(tag.id));
      } else {
        // Parent not found - treat as root
        roots.push(tagMap.get(tag.id));
      }
    }
  });

  // Sort all nodes by name (case-insensitive)
  const sortByName = (a, b) => {
    const nameA = (a.content.name || a.name || a.id).toLowerCase();
    const nameB = (b.content.name || b.name || b.id).toLowerCase();
    return nameA.localeCompare(nameB);
  };

  roots.sort(sortByName);
  tagMap.forEach(node => node.children.sort(sortByName));

  return roots;
}

/**
 * Gets display name for a tag node
 * @param {Object} tagNode - Tag node from tree
 * @returns {string} Display name
 */
export function getTagName(tagNode) {
  return tagNode.content.name || tagNode.name || tagNode.id;
}

/**
 * Gets color for a tag node
 * @param {Object} tagNode - Tag node from tree
 * @returns {string} Hex color code
 */
export function getTagColor(tagNode) {
  return tagNode.content.color || '#3b82f6';
}

// hobson-instance renderer - iframe-based isolation
export async function render(item, api) {
  // Build full instance ID by chaining current prefix with this item's ID
  const currentInstanceId = api.getInstanceId();
  const instanceId = currentInstanceId ? `${currentInstanceId}:${item.id}` : item.id;

  // Container element
  const container = document.createElement('div');
  container.style.cssText = `
    width: 100%;
    height: 100%;
    border: 2px solid #0066cc;
    border-radius: 4px;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    background: #f5f5f5;
  `;

  // Header showing this is a nested instance
  const header = document.createElement('div');
  header.style.cssText = `
    background: #0066cc;
    color: white;
    padding: 8px 12px;
    font-size: 12px;
    font-weight: bold;
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-shrink: 0;
  `;

  const title = document.createElement('span');
  title.textContent = `Nested: ${item.name || instanceId.slice(0, 8)}...`;
  header.appendChild(title);

  // Controls
  const controls = document.createElement('div');
  controls.style.cssText = 'display: flex; gap: 8px;';

  // Reload button
  const reloadBtn = document.createElement('button');
  reloadBtn.textContent = 'Reload';
  reloadBtn.style.cssText = 'padding: 4px 12px; background: white; color: #0066cc; border: none; border-radius: 3px; cursor: pointer; font-size: 11px;';
  reloadBtn.onclick = () => {
    iframe.src = iframe.src; // Force reload
  };
  controls.appendChild(reloadBtn);

  // Open in new tab button
  const newTabBtn = document.createElement('button');
  newTabBtn.textContent = 'Open in Tab';
  newTabBtn.style.cssText = 'padding: 4px 12px; background: white; color: #0066cc; border: none; border-radius: 3px; cursor: pointer; font-size: 11px;';
  newTabBtn.onclick = () => {
    window.open(iframe.src, '_blank');
  };
  controls.appendChild(newTabBtn);

  header.appendChild(controls);

  // Loading indicator
  const loading = document.createElement('div');
  loading.style.cssText = `
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    color: #666;
    font-size: 14px;
  `;
  loading.textContent = 'Loading nested instance...';

  // Iframe container (for positioning)
  const iframeContainer = document.createElement('div');
  iframeContainer.style.cssText = `
    flex: 1;
    position: relative;
    overflow: hidden;
  `;
  iframeContainer.appendChild(loading);

  // Create iframe pointing to bootstrap with instance parameter
  const iframe = document.createElement('iframe');
  const bootstrapPath = window.location.pathname;
  iframe.src = `${bootstrapPath}?instance=${encodeURIComponent(instanceId)}`;
  iframe.style.cssText = `
    width: 100%;
    height: 100%;
    border: none;
    opacity: 0;
    transition: opacity 0.2s;
  `;

  // Show iframe once loaded
  iframe.onload = () => {
    loading.style.display = 'none';
    iframe.style.opacity = '1';
  };

  iframe.onerror = () => {
    loading.textContent = 'Failed to load nested instance';
    loading.style.color = '#cc0000';
  };

  iframeContainer.appendChild(iframe);

  container.appendChild(header);
  container.appendChild(iframeContainer);

  return container;
}

export async function render(item, api) {
  const container = api.createElement('div', { style: 'padding: 15px;' }, []);

  // Header
  const header = api.createElement('h3', { style: 'margin-top: 0;' }, [
    item.name || 'Untitled Script'
  ]);
  container.appendChild(header);

  // Description
  if (item.content.description) {
    const desc = api.createElement('p', { style: 'color: #666; font-style: italic;' }, [
      item.content.description
    ]);
    container.appendChild(desc);
  }

  // Code display
  const code = api.createElement('pre', {
    style: `
      background: #f8f8f8;
      padding: 15px;
      border-radius: 4px;
      border: 1px solid #ddd;
      overflow-x: auto;
      font-family: 'SF Mono', Monaco, monospace;
      font-size: 13px;
      line-height: 1.5;
    `
  }, [item.content.code || '// No code']);
  container.appendChild(code);

  // Buttons
  const buttons = api.createElement('div', { 
    style: 'margin-top: 15px; display: flex; gap: 10px;' 
  }, []);

  const runBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px; font-weight: 500;',
    onclick: async () => {
      runBtn.disabled = true;
      runBtn.textContent = 'Running...';

      try {
        // Get the REPL API which has the helper functions
        const replApi = api.createREPLContext();

        // Execute the script code with REPL API
        const asyncFn = new Function('api', `
          return (async () => {
            ${item.content.code}
          })();
        `);

        const result = await asyncFn(replApi);
        alert('Script executed!\n\nResult: ' + (
          result !== undefined 
            ? JSON.stringify(result, null, 2) 
            : 'No return value'
        ));
      } catch (error) {
        alert('Error executing script:\n\n' + error.message);
      } finally {
        runBtn.disabled = false;
        runBtn.textContent = 'Run Script';
      }
    }
  }, ['Run Script']);
  buttons.appendChild(runBtn);

  const editBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      // Navigate to raw editor for this item
      api.editRaw(item.id);
    }
  }, ['Edit']);
  buttons.appendChild(editBtn);

  const copyBtn = api.createElement('button', {
    style: 'padding: 10px 20px; cursor: pointer;',
    onclick: () => {
      navigator.clipboard.writeText(item.content.code);
      copyBtn.textContent = 'Copied!';
      setTimeout(() => copyBtn.textContent = 'Copy Code', 1000);
    }
  }, ['Copy Code']);
  buttons.appendChild(copyBtn);

  container.appendChild(buttons);

  return container;
}

export function render(value, options, api) {
  const { mode, onChange, label, format = 'full' } = options;
  const wrapper = api.createElement('div', { className: 'field-timestamp' });
  wrapper.style.cssText = 'display: flex; flex-direction: column; gap: 4px;';

  if (label) {
    const labelEl = api.createElement('label');
    labelEl.textContent = label;
    labelEl.style.cssText = 'font-weight: 500; font-size: 14px; color: #333;';
    wrapper.appendChild(labelEl);
  }

  const formatTimestamp = (ts) => {
    if (!ts) return '';
    const date = new Date(ts);
    if (format === 'date') return date.toLocaleDateString();
    if (format === 'time') return date.toLocaleTimeString();
    if (format === 'relative') {
      const diff = Date.now() - ts;
      const mins = Math.floor(diff / 60000);
      const hrs = Math.floor(mins / 60);
      const days = Math.floor(hrs / 24);
      if (days > 0) return days + ' day' + (days > 1 ? 's' : '') + ' ago';
      if (hrs > 0) return hrs + ' hour' + (hrs > 1 ? 's' : '') + ' ago';
      if (mins > 0) return mins + ' minute' + (mins > 1 ? 's' : '') + ' ago';
      return 'just now';
    }
    return date.toLocaleString();
  };

  if (mode === 'editable' && onChange) {
    const input = api.createElement('input', { type: 'datetime-local', style: 'padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 14px;' });
    if (value) input.value = new Date(value).toISOString().slice(0, 16);
    input.onchange = (e) => onChange(e.target.value ? new Date(e.target.value).getTime() : null);
    wrapper.appendChild(input);
  } else {
    const span = api.createElement('span');
    span.textContent = formatTimestamp(value);
    span.style.cssText = 'padding: 8px; background: #f5f5f5; border-radius: 4px; font-size: 14px; color: #666;';
    wrapper.appendChild(span);
  }
  return wrapper;
}

// Hobson-flavored markdown renderer
// Handles item:// links, transclusions, and query blocks

// Helper: Escape HTML for safe attribute values
const escapeHtml = (str) => {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
};

// Helper: Parse item URL
const parseItemUrl = (url) => {
  const match = url.match(/item:\/\/([a-f0-9\-]+)(?:#([^?]+))?(?:\?(.+))?/);
  if (!match) return null;
  const itemId = match[1];
  const fragment = match[2] || null;
  const queryString = match[3] || null;
  const queryParams = {};
  if (queryString) {
    queryString.split('&').forEach(pair => {
      const [key, val] = pair.split('=');
      queryParams[key] = val;
    });
  }
  return { itemId, fragment, queryParams };
};

// Helper: Get field value from item
const getFieldValue = (item, fieldName) => {
  if (fieldName === 'name') return item.name || '';
  if (fieldName === 'content') return JSON.stringify(item.content, null, 2);
  return item.content?.[fieldName] || '';
};

// Helper: Extract named region from text
const extractRegion = (text, regionName) => {
  const lines = text.split('\n');
  const beginMarker = '[BEGIN:' + regionName + ']';
  const endMarker = '[END:' + regionName + ']';
  let beginIdx = -1, endIdx = -1;
  for (let i = 0; i < lines.length; i++) {
    const cleaned = lines[i].trim().replace(/^\/\/\s*/, '').replace(/^#\s*/, '').replace(/^<!--\s*/, '').replace(/\s*-->$/, '').trim();
    if (cleaned === beginMarker) beginIdx = i;
    else if (cleaned === endMarker && beginIdx >= 0) { endIdx = i; break; }
  }
  if (beginIdx === -1 || endIdx === -1) throw new Error('Region not found: ' + regionName);
  return { text: lines.slice(beginIdx + 1, endIdx).join('\n'), startLine: beginIdx + 2 };
};

// Helper: Apply line range to text
const applyLineRange = (text, linesParam, baseStartLine = 1) => {
  if (!linesParam) return { text, startLine: baseStartLine };
  const lines = text.split('\n');
  let startLine, endLine;
  if (linesParam.includes('-')) {
    const parts = linesParam.split('-');
    startLine = parts[0] ? parseInt(parts[0]) : 1;
    endLine = parts[1] ? parseInt(parts[1]) : lines.length;
  } else {
    startLine = endLine = parseInt(linesParam);
  }
  const start = Math.max(0, startLine - 1);
  const end = Math.min(lines.length, endLine);
  return { text: lines.slice(start, end).join('\n'), startLine: baseStartLine + start };
};

/**
 * Render markdown with Hobson extensions.
 * @param {string} markdown - The markdown text to render
 * @param {object} api - The Hobson API object
 * @returns {Promise<HTMLElement>} - A div containing the rendered markdown
 */
export async function render(markdown, api) {
  const md = markdown || '';

  // Load markdown-it
  await api.require('markdown-it');
  const markdownitModule = await api.require('markdown-it-wrapper');
  const markdownit = markdownitModule.default;

  // Configure link rendering for item:// links and external links
  const renderer = markdownit.renderer;
  const defaultLinkRender = renderer.rules.link_open || function(tokens, idx, opts, env, self) {
    return self.renderToken(tokens, idx, opts);
  };

  renderer.rules.link_open = function(tokens, idx, opts, env, self) {
    const token = tokens[idx];
    const hrefIndex = token.attrIndex('href');
    if (hrefIndex >= 0) {
      const href = token.attrs[hrefIndex][1];
      if (href.startsWith('item://')) {
        token.attrSet('data-item-link', href);
        token.attrSet('href', '#');
      } else if (href.startsWith('http://') || href.startsWith('https://')) {
        // External links open in new tab
        token.attrSet('target', '_blank');
        token.attrSet('rel', 'noopener noreferrer');
      }
    }
    return defaultLinkRender(tokens, idx, opts, env, self);
  };

  // Render markdown to HTML
  let html = markdownit.render(md);

  // Process region markers: emit invisible anchor spans for [BEGIN:name] markers
  // This allows scroll-to-region navigation in rendered markdown
  html = html.replace(
    /<!--\s*\[BEGIN:([^\]]+)\]\s*-->/g,
    (match, regionName) => {
      return `<span data-region-start="${escapeHtml(regionName)}" style="display:none;"></span>${match}`;
    }
  );

  const content = api.createElement('div', { className: 'markdown-content' });
  content.style.cssText = 'line-height: 1.8; font-size: 16px;';
  content.innerHTML = html;

  // Handle item:// link clicks - open as sibling in current container, or navigate if root
  const links = content.querySelectorAll('a[data-item-link]');
  links.forEach(link => {
    const href = link.getAttribute('data-item-link');
    const parsed = parseItemUrl(href);
    if (parsed) {
      link.onclick = (e) => {
        e.preventDefault();
        // Build navigateTo params from URL fragment and query params
        const navigateTo = {
          field: parsed.fragment,
          line: parsed.queryParams.lines ? parseInt(parsed.queryParams.lines) : null,
          region: parsed.queryParams.region || null
        };
        const hasNavigation = navigateTo.field || navigateTo.line || navigateTo.region;

        if (api.siblingContainer) {
          api.siblingContainer.addSibling(parsed.itemId, hasNavigation ? navigateTo : null);
        } else {
          api.navigate(parsed.itemId, hasNavigation ? navigateTo : null);
        }
      };
      link.style.cssText = 'color: #007bff; text-decoration: none; border-bottom: 1px solid #007bff; cursor: pointer;';
    }
  });

  // Handle transclusions (images with item:// src)
  const transclusionImages = content.querySelectorAll('img[src^="item://"]');
  for (const img of transclusionImages) {
    const fullUrl = img.src.replace(/^.*item:\/\//, 'item://');
    const parsed = parseItemUrl(fullUrl);
    const altText = img.alt;

    if (!parsed) {
      const errorDiv = api.createElement('div');
      errorDiv.style.cssText = 'background: #fff3cd; border: 1px solid #ffc107; border-radius: 4px; padding: 8px 12px; margin: 10px 0; color: #856404; font-style: italic;';
      errorDiv.textContent = '[Invalid URL: ' + altText + ']';
      img.parentNode.replaceChild(errorDiv, img);
      continue;
    }

    try {
      const transcludedItem = await api.get(parsed.itemId);
      const isPartial = parsed.fragment || Object.keys(parsed.queryParams).length > 0;

      const wrapperDiv = api.createElement('div', { className: 'transclusion-container' });
      wrapperDiv.style.cssText = 'background: #f9f9f9; border: 1px solid #e0e0e0; border-radius: 6px; padding: 15px; margin: 15px 0;';

      if (isPartial) {
        // Partial transclusion
        const fieldName = parsed.fragment || 'content';
        let fieldValue = getFieldValue(transcludedItem, fieldName);
        if (!fieldValue) throw new Error('Field not found: ' + fieldName);

        let text, startLine = 1;
        if (parsed.queryParams.region) {
          const regionResult = extractRegion(fieldValue, parsed.queryParams.region);
          text = regionResult.text;
          startLine = regionResult.startLine;
        } else {
          text = fieldValue;
        }

        if (parsed.queryParams.lines) {
          const rangeResult = applyLineRange(text, parsed.queryParams.lines, startLine);
          text = rangeResult.text;
          startLine = rangeResult.startLine;
        }

        let headerDesc = transcludedItem.name || transcludedItem.id;
        if (parsed.fragment) {
          headerDesc += ' (#' + parsed.fragment;
          if (parsed.queryParams.region) headerDesc += ', region=' + parsed.queryParams.region;
          if (parsed.queryParams.lines) headerDesc += ', lines=' + parsed.queryParams.lines;
          headerDesc += ')';
        }

        const header = api.createElement('div');
        header.style.cssText = 'font-size: 12px; color: #666; margin-bottom: 10px; padding-bottom: 8px; border-bottom: 1px solid #ddd; cursor: pointer;';
        header.textContent = 'Transcluded from: ' + headerDesc;
        header.onclick = () => api.siblingContainer.addSibling(parsed.itemId);
        wrapperDiv.appendChild(header);

        const pre = api.createElement('pre');
        pre.style.cssText = 'margin: 0; padding: 10px; background: #fff; border-radius: 4px; overflow-x: auto; font-family: monospace; font-size: 13px; line-height: 1.5;';

        const code = api.createElement('code');
        const lines = text.split('\n');
        lines.forEach((line, idx) => {
          const lineNum = startLine + idx;
          const lineNumSpan = api.createElement('span');
          lineNumSpan.style.cssText = 'display: inline-block; width: 40px; color: #999; user-select: none; text-align: right; margin-right: 10px;';
          lineNumSpan.textContent = lineNum + '';
          code.appendChild(lineNumSpan);
          code.appendChild(document.createTextNode(line));
          if (idx < lines.length - 1) code.appendChild(document.createTextNode('\n'));
        });

        pre.appendChild(code);
        wrapperDiv.appendChild(pre);
      } else {
        // Full transclusion
        const header = api.createElement('div');
        header.style.cssText = 'font-size: 12px; color: #666; margin-bottom: 10px; padding-bottom: 8px; border-bottom: 1px solid #ddd; cursor: pointer;';
        header.textContent = 'Transcluded from: ' + (transcludedItem.name || transcludedItem.id);
        header.onclick = () => api.navigate(parsed.itemId);
        wrapperDiv.appendChild(header);

        const renderedContent = await api.renderItem(parsed.itemId);
        wrapperDiv.appendChild(renderedContent);
      }

      img.parentNode.replaceChild(wrapperDiv, img);
    } catch (err) {
      const errorDiv = api.createElement('div');
      errorDiv.style.cssText = 'background: #fff3cd; border: 1px solid #ffc107; border-radius: 4px; padding: 8px 12px; margin: 10px 0; color: #856404; font-style: italic;';
      errorDiv.textContent = '[Missing: ' + altText + ' - ' + err.message + ']';
      img.parentNode.replaceChild(errorDiv, img);
    }
  }

  // Handle query blocks (```query ... ```)
  const queryBlocks = content.querySelectorAll('pre > code.language-query');
  for (const codeBlock of queryBlocks) {
    const pre = codeBlock.parentElement;
    const queryCode = codeBlock.textContent;

    try {
      // Helper: wrap content with transclusion chrome
      const transclude = (item, text, options = {}) => {
        const chrome = options.chrome || 'subtle';
        const itemId = typeof item === 'string' ? item : item.id;
        const itemName = typeof item === 'string' ? itemId : (item.name || itemId);
        if (chrome === 'none') return text;
        if (chrome === 'full') {
          return `<div class="query-transclude-full" data-item-id="${escapeHtml(itemId)}" data-item-name="${escapeHtml(itemName)}">\n\n${text}\n\n</div>`;
        }
        // Subtle chrome: append a link marker (doesn't interfere with markdown list processing)
        return `${text} [↗](transclude://${itemId}?name=${encodeURIComponent(itemName)})`;
      };

      // Helper: apply transclude to each item
      const transcludeEach = (items, formatter, options = {}) => {
        return items.map(item => transclude(item, formatter(item), options)).join('\n');
      };

      // Execute the query code with api and helpers in scope
      const AsyncFunction = Object.getPrototypeOf(async function(){}).constructor;
      const fn = new AsyncFunction('api', 'transclude', 'transcludeEach', queryCode);
      const result = await fn(api, transclude, transcludeEach);

      // Render the result as markdown
      const resultHtml = markdownit.render(result || '');
      const resultDiv = api.createElement('div', { className: 'query-result' });
      resultDiv.innerHTML = resultHtml;

      // Process item:// links in the query result
      const resultLinks = resultDiv.querySelectorAll('a[data-item-link]');
      resultLinks.forEach(link => {
        const href = link.getAttribute('data-item-link');
        const parsed = parseItemUrl(href);
        if (parsed) {
          link.onclick = (e) => {
            e.preventDefault();
            const navigateTo = {
              field: parsed.fragment,
              line: parsed.queryParams.lines ? parseInt(parsed.queryParams.lines) : null,
              region: parsed.queryParams.region || null
            };
            const hasNavigation = navigateTo.field || navigateTo.line || navigateTo.region;

            if (api.siblingContainer) {
              api.siblingContainer.addSibling(parsed.itemId, hasNavigation ? navigateTo : null);
            } else {
              api.navigate(parsed.itemId, hasNavigation ? navigateTo : null);
            }
          };
          link.style.cssText = 'color: #007bff; text-decoration: none; border-bottom: 1px solid #007bff; cursor: pointer;';
        }
      });

      // Process transclude:// links (subtle chrome)
      const transcludeLinks = resultDiv.querySelectorAll('a[href^="transclude://"]');
      for (const link of transcludeLinks) {
        const href = link.getAttribute('href');
        const match = href.match(/^transclude:\/\/([^?]+)\?name=(.+)$/);
        if (match) {
          const itemId = match[1];
          const itemName = decodeURIComponent(match[2]);

          // Style as subtle chrome
          link.style.cssText = 'color: #999; font-size: 0.75em; margin-left: 3px; cursor: pointer; text-decoration: none; vertical-align: super;';
          link.title = 'From: ' + itemName;
          link.onclick = (e) => {
            e.preventDefault();
            if (api.siblingContainer) {
              api.siblingContainer.addSibling(itemId);
            } else {
              api.navigate(itemId);
            }
          };
        }
      }

      // Process full transclusion markers
      const fullMarkers = resultDiv.querySelectorAll('.query-transclude-full');
      for (const marker of fullMarkers) {
        const itemId = marker.getAttribute('data-item-id');
        const itemName = marker.getAttribute('data-item-name');

        // Create full chrome wrapper
        const wrapperDiv = api.createElement('div', { className: 'transclusion-container' });
        wrapperDiv.style.cssText = 'background: #f9f9f9; border: 1px solid #e0e0e0; border-radius: 6px; padding: 15px; margin: 15px 0;';

        const header = api.createElement('div');
        header.style.cssText = 'font-size: 12px; color: #666; margin-bottom: 10px; padding-bottom: 8px; border-bottom: 1px solid #ddd; cursor: pointer;';
        header.textContent = 'From: ' + itemName;
        header.onclick = () => api.siblingContainer?.addSibling(itemId);
        wrapperDiv.appendChild(header);

        // Move marker contents into wrapper
        const contentDiv = api.createElement('div');
        while (marker.firstChild) {
          contentDiv.appendChild(marker.firstChild);
        }
        wrapperDiv.appendChild(contentDiv);

        marker.parentNode.replaceChild(wrapperDiv, marker);
      }

      // Replace the pre block with the result
      pre.parentNode.replaceChild(resultDiv, pre);

    } catch (err) {
      const errorDiv = api.createElement('div');
      errorDiv.style.cssText = 'background: #ffebee; border: 1px solid #f44336; border-radius: 4px; padding: 8px 12px; margin: 10px 0; color: #c62828;';
      errorDiv.textContent = '[Query error: ' + err.message + ']';
      pre.parentNode.replaceChild(errorDiv, pre);
    }
  }

  return content;
}

/**
 * Shows a modal dialog for selecting an item type.
 * @param {Object} api - The Hobson API object
 * @returns {Promise<string|null>} - The selected type ID, or null if cancelled
 */
export async function showTypePicker(api) {
  const modalLib = await api.require('modal-lib');

  const allItems = await api.getAll();
  const types = allItems.filter(i => i.type === api.IDS.TYPE_DEFINITION);

  return new Promise((resolve) => {
    const { close } = modalLib.showModal({
      title: 'Select Item Type',
      width: '500px',
      maxHeight: '600px',
      api,
      onClose: () => resolve(null),
      content: ({ close: closeModal }) => {
        const typeList = api.createElement('div', {
          style: 'display: flex; flex-direction: column; gap: 8px;'
        }, []);

        for (const type of types) {
          const typeBtn = api.createElement('button', {
            style: 'padding: 12px; text-align: left; border: 1px solid #ddd; border-radius: 4px; background: white; cursor: pointer;',
            onclick: () => {
              resolve(type.id);
              closeModal();
            }
          }, []);

          // Hover effect
          typeBtn.onmouseover = () => { typeBtn.style.background = '#f5f5f5'; };
          typeBtn.onmouseout = () => { typeBtn.style.background = 'white'; };

          const typeName = api.createElement('div', { style: 'font-weight: bold;' }, [type.name || type.id.slice(0, 8)]);
          typeBtn.appendChild(typeName);

          if (type.content?.description) {
            const typeDesc = api.createElement('div', { style: 'font-size: 12px; color: #666; margin-top: 4px;' }, [type.content.description]);
            typeBtn.appendChild(typeDesc);
          }

          typeList.appendChild(typeBtn);
        }

        return typeList;
      }
    });
  });
}

