  // Get current item name
  let currentName = itemId ? itemId.slice(0, 8) + '...' : '(none)';
  let itemExists = false;
  if (itemId) {
    try {
      const refItem = await api.get(itemId);
      currentName = refItem.name || refItem.id;
      itemExists = true;
    } catch (e) {
      currentName = itemId.slice(0, 8) + '... (not found)';
