  errorDisplay.style.cssText = 'color: #c00; font-size: 13px; margin-top: 8px; display: none;';
  editorArea.appendChild(errorDisplay);

  modal.appendChild(editorArea);

  // Actions
  const actions = document.createElement('div');
  actions.style.cssText = 'padding: 16px 20px; border-top: 1px solid #ddd; display: flex; gap: 10px; justify-content: flex-end;';

  const cancelBtn = document.createElement('button');
  cancelBtn.textContent = 'Cancel';
  cancelBtn.style.cssText = 'padding: 8px 16px; cursor: pointer; border: 1px solid #ccc; background: white; border-radius: 4px;';
  cancelBtn.onclick = () => hide();
  actions.appendChild(cancelBtn);

  const saveBtn = document.createElement('button');
  saveBtn.textContent = 'Save';
  saveBtn.style.cssText = 'padding: 8px 16px; cursor: pointer; border: none; background: #007bff; color: white; border-radius: 4px;';
  saveBtn.onclick = async () => {
    try {
      const updated = JSON.parse(textarea.value);
      errorDisplay.style.display = 'none';

      // Save the item
      await localApi.update(updated);

      // Clear module cache if it's a code item
      if (updated.type === localApi.IDS?.CODE || 
          updated.type === localApi.IDS?.LIBRARY || 
          updated.type === localApi.IDS?.VIEW ||
          updated.type === localApi.IDS?.KERNEL_MODULE) {
        // Module cache will be cleared by saveItem
      }

      hide();
    } catch (error) {
      errorDisplay.textContent = 'JSON Error: ' + error.message;
      errorDisplay.style.display = 'block';
    }
  };
  actions.appendChild(saveBtn);

  modal.appendChild(actions);
  overlay.appendChild(modal);

  // Close on overlay click
  overlay.onclick = (e) => {
    if (e.target === overlay) hide();
  };

  // Close on Escape, Cmd+Enter to save
  const keyHandler = (e) => {
    if (e.key === 'Escape') {
      hide();
      document.removeEventListener('keydown', keyHandler);
    }
    if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
      e.preventDefault();
      saveBtn.click();
    }
  };
  document.addEventListener('keydown', keyHandler);

  document.body.appendChild(overlay);
  textarea.focus();

  // Select all for easy replacement
  textarea.select();
}

export function hide() {
  const existing = document.getElementById('json-editor-overlay');
  if (existing) {
    existing.remove();
  }
}

// hobson-instance-lifecycle
// Handles cascade delete when a hobson-instance is deleted

export async function onItemDeleted({ id, item }, api) {
  console.log(`Hobson instance deleted: ${item.name || id}. Cleaning up nested items...`);

  // Get all items including nested (raw) to find items with this prefix
  // In parent context, getAllRaw returns items with their full prefixed IDs
  const allItems = await api.getAllRaw();
  const prefix = id + ':';
  const nestedItems = allItems.filter(i => i.id.startsWith(prefix));

  if (nestedItems.length === 0) {
    console.log('No nested items to clean up.');
    return;
  }

  console.log(`Found ${nestedItems.length} nested items to delete...`);

  // Delete each nested item
  // The IDs from getAllRaw are already the full prefixed IDs (e.g., "instance-abc:kernel-core")
  for (const nestedItem of nestedItems) {
    try {
      await api.delete(nestedItem.id);
    } catch (e) {
      console.warn(`Failed to delete nested item ${nestedItem.id}:`, e.message);
    }
  }

  console.log(`Cleaned up ${nestedItems.length} nested items from instance ${item.name || id}.`);
}

